          const output = r2.result?.output ? `
\`\`\`
${r2.result.output.substring(0, 300)}${r2.result.output.length > 300 ? "..." : ""}
\`\`\`` : "";
          const error = r2.result?.error ? `
⚠️ ${r2.result.error.substring(0, 200)}` : "";
